import{_ as t,o as i,c as o,am as a}from"./chunks/framework.foOaJFbm.js";const u=JSON.parse('{"title":"S_TIDE | A comprehensive toolbox for tidal analysis","titleTemplate":"S_TIDE","description":"","frontmatter":{"layout":"home","title":"S_TIDE | A comprehensive toolbox for tidal analysis","titleTemplate":"S_TIDE","hero":{"name":"S_TIDE","text":"Tidal Analysis Toolbox","tagline":"for oceanographic research, developed by Dr. Haidong Pan in MATLAB.","image":{"src":"S_Tide-logo3.svg","alt":"S_TIDE LOGO"},"actions":[{"theme":"brand","text":"Download","link":"/download/"},{"theme":"brand","text":"User Guide","link":"/user-guide/"},{"theme":"alt","text":"Publications","link":"/publications/"},{"theme":"alt","text":"About","link":"/about/"}],"description":"","features":[],"head":[]},"features":[{"icon":"🐱","title":"Open","details":"All code is open-sourced under the MIT license and follows open standards and protocols."},{"icon":"📊","title":"Comprehensive","details":"S_TIDE provides a wide range of tidal analysis methods, including harmonic analysis, tidal prediction, and more."},{"icon":"🧑‍🤝‍🧑","title":"User-Friendly","details":"Designed for ease of use, S_TIDE includes a user-friendly interface and extensive documentation."}],"description":"","navbar":true,"sideBar":true,"footer":true,"outline":[1,3],"editLink":true,"lastUpdated":true,"aside":"right","custom":{}},"headers":[],"relativePath":"index.md","filePath":"index.md","lastUpdated":1772429025000}'),n={name:"index.md"};function r(s,e,p,l,d,c){return i(),o("div",null,[...e[0]||(e[0]=[a(`<p>Poems for S_TIDE</p><pre><code>S_TIDE: My Homer Epic
</code></pre><p>I am currently rewriting Homer&#39;s Epic in MATLAB.</p><p>Every function is a contemporary odyssey sailing ship,</p><p>Every bug fix is a test through Sirens Song,</p><p>Every user growth is an adventure to a new academic island.</p><p>When you realize that you are both Homer and Odysseus, the true legacy begins!</p><p>Not to become the hero of an epic, but to become the one who keeps rewriting it.</p><p>In Tolkien&#39;s Middle-earth, the greatest thing is not the Silmarillion, but the fire of inheritance that every ordinary hobbit carries.</p><p>The real stars are not in the sky, but in the eyes of every researcher who uses S_TIDE kit.</p><p>One day, S_TIDE will become the Rosetta Stone for an alien civilization to decipher the earth&#39;s tides.</p><p>The efforts at this moment will be turned into a knowing smile on a light-year scale.</p><p>写给S_TIDE的诗</p><pre><code>S_TIDE:我的《荷马史诗》
</code></pre><p>我正在用MATLAB语言重写《荷马史诗》，</p><p>每个函数都是当代的奥德赛帆船，</p><p>每个bug修复都是穿越塞壬之歌的考验，</p><p>每次用户增长都是抵达新学术岛屿的探险。</p><p>当意识到自己既是荷马又是奥德修斯时，真正的传承就开始了！</p><p>不是成为史诗中的英雄，而是成为那个不断重写史诗的人。</p><p>在托尔金的中土世界，最伟大的不是精灵宝钻，而是每个平凡霍比特人怀揣的传承之火。</p><p>真正的星辰不在天上，而在每个使用S_TIDE工具包的研究者眼中闪烁的灵光。</p><p>终有一天，S_TIDE会成为某个外星文明破译地球潮汐的罗塞塔石碑，</p><p>此刻的努力都将化作光年尺度上的会心一笑。</p>`,24)])])}const m=t(n,[["render",r]]);export{u as __pageData,m as default};
